  ('social-worker-moex-00324', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作者與服務對象會談的相對保密，下列敘述何者錯誤？', '["徵詢法律意見或個案研討", "服務對象有明顯的自我傷害", "非機構發言人，在網路上回應對機構服務對象之質疑言論", "警告極有可能被服務對象傷害的第三人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00325', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某一社會工作者緊急安置保護某位兒少一段時間之後，面臨個案父母施壓想帶回兒少，社會工作 者在查詢紀錄後，發現已經緊急安置兒少6個月了，此時社會工作者會被視為有違反何種倫理的 風險窘境？', '["怠職", "瀆職", "濫權", "溺職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00326', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為解決案主所面臨的問題，社會工作者運用「增強權能」觀點，發展與增強服務使用者三方面的 力量，有關此三方面的力量，下列何者錯誤？', '["生物／基因", "個人", "人際", "政治／社區"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00327', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於「專業倫理守則」的敘述，下列何者錯誤？', '["指一個專業團體以集體自律的方式所訂定的守則或公約", "以理論為中心，在施行上與個人價值相同", "要求全體專業會員共同遵守的行為規範", "通常對會員有強大而直接的約束力量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00328', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '未滿18歲服務對象就醫時，醫生診治時發現疑似性侵案，通知社會工作者陪同就醫，但服務對象 私下向社工表示是其和伴侶合意性行為，希望社工能保密。上述情境屬於何種倫理困境？', '["尊重案主自決與法律規定責任通報的兩難", "真誠原則與保護生命原則的兩難", "不傷害原則與行善原則的兩難", "保護生命原則與自由自主原則的兩難"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00329', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關幸福權中，人類社會三個根本「善」（goods）的敘述，下列何者正確？', '["擁有支持性的社會網絡是一種「外在善」（externalgoods）", "發展個人的自尊是一種「累加善」（additivegoods）", "維持穩定的住所和營養是一種「維持善」（nonsubtractivegoods）", "擁有親密的好友和寵物是一種「基本善」（basicgoods）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00330', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當兒少的原生家庭發生重大變故，因父母嚴重疏忽或虐待不適宜教養子女，透過社會工作者之協 助，將兒少安置在政府核可的家庭，等問題改善，再重回其原生家庭。此種安排稱為？', '["收養", "出養", "寄養", "認養"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
